type ValidationSuccess = {
  valid: true;
  email: string;
  local: string;
  domain: string;
};

type ValidationFailure = {
  valid: false;
  email: string;
  error: string;
};

type ValidationResult = ValidationSuccess | ValidationFailure;

function validateEmail(email: string): ValidationResult {
  const trimmed = email.trim();

  if (trimmed.length === 0) {
    return { valid: false, email: trimmed, error: "Email cannot be empty" };
  }

  const atIndex = trimmed.lastIndexOf("@");

  if (atIndex === -1) {
    return { valid: false, email: trimmed, error: "Missing @ symbol" };
  }

  const local = trimmed.slice(0, atIndex);
  const domain = trimmed.slice(atIndex + 1);

  if (local.length === 0) {
    return { valid: false, email: trimmed, error: "Local part cannot be empty" };
  }

  if (local.length > 64) {
    return { valid: false, email: trimmed, error: "Local part exceeds 64 characters" };
  }

  if (domain.length === 0) {
    return { valid: false, email: trimmed, error: "Domain cannot be empty" };
  }

  if (domain.length > 253) {
    return { valid: false, email: trimmed, error: "Domain exceeds 253 characters" };
  }

  if (!domain.includes(".")) {
    return { valid: false, email: trimmed, error: "Domain must contain at least one dot" };
  }

  const domainParts = domain.split(".");
  for (const part of domainParts) {
    if (part.length === 0) {
      return { valid: false, email: trimmed, error: "Domain contains empty label" };
    }
    if (part.length > 63) {
      return { valid: false, email: trimmed, error: "Domain label exceeds 63 characters" };
    }
    if (!/^[a-zA-Z0-9-]+$/.test(part)) {
      return { valid: false, email: trimmed, error: "Domain contains invalid characters" };
    }
    if (part.startsWith("-") || part.endsWith("-")) {
      return { valid: false, email: trimmed, error: "Domain label cannot start or end with hyphen" };
    }
  }

  if (!/^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+$/.test(local)) {
    return { valid: false, email: trimmed, error: "Local part contains invalid characters" };
  }

  if (local.startsWith(".") || local.endsWith(".")) {
    return { valid: false, email: trimmed, error: "Local part cannot start or end with a dot" };
  }

  if (local.includes("..")) {
    return { valid: false, email: trimmed, error: "Local part cannot contain consecutive dots" };
  }

  return { valid: true, email: trimmed, local, domain };
}

export { validateEmail, ValidationResult, ValidationSuccess, ValidationFailure };
